def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # Correct initialization for inclusive search space [left, right]
    while left <= right:         # Standard template uses left <= right
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1  # Move left pointer past mid
        else:
            right = mid - 1 # Move right pointer before mid
